string GenerateTestCase(int m, int n, Random? random = null)
{
    random = random ?? new Random();
    StringBuilder testCase = new();

    testCase.Append('[');

    for (int row = 0; row < m; row++)
    {
        if (row > 0)
        {
            testCase.Append(',');
        }
        testCase.Append('[');

        for (int col = 0; col < n; col++)
        {
            if (col > 0)
            {
                testCase.Append(',');
            }

            testCase.Append(random.Next(2));
        }

        testCase.Append(']');
    }

    testCase.Append(']');

    return testCase.ToString();
}